import sys

class Solution:
  def solve(self, stack: list[int], n: int, target: int) -> int:
    while n > 0:
      n -= 1
      if stack[n] == target:
        return 1
    return 0



def main():
  t = 1
  for _ in range(t):
    stack = list(map(int, input().split()))
    n = int(input())
    target = int(input())
    s = Solution()
    result = s.solve(stack, n, target)
    print(result)

if __name__ == '__main__':
  main()

