#include <iostream>
#include <vector>
using namespace std;
class Solution {
public:
  int solve(vector<int>& stack, int n, int target) {
    while (n > 0) {
      n--; 
      if (stack[n] == target) return 1;
    }
    return 0;
  }
};

int main() {
  int S;
  cin >> S;
  int n;
  cin >> n;
  int target;
  cin >> target;
  Solution s;
  vector<int> stack(S);
  for (int i = 0; i < S; i++) {
    int x;
    cin >> x;
    stack[i] = x;
  }
  int result = s.solve(stack, n, target);
  cout << result << endl;
  return 0;
}
